import React from 'react';
import { Badge } from '../design-system/Badge/Badge';
import { Card } from '../design-system/Card/Card';

interface PatientHeaderProps {
  name: string;
  dob: string;
  age: number;
  hin: string;
  sex: string;
  providerName?: string;
  allergies?: string[];
}

export const PatientHeader: React.FC<PatientHeaderProps> = ({
  name, dob, age, hin, sex, providerName, allergies = [],
}) => (
  <div style={{
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: 'var(--spacing-3) var(--spacing-4)',
    backgroundColor: 'var(--color-primary-600)', color: '#fff',
    minHeight: 48, position: 'sticky', top: 0, zIndex: 100,
  }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--spacing-3)' }}>
      <strong style={{ fontSize: 'var(--font-size-lg)' }}>{name}</strong>
      <span style={{ opacity: 0.8, fontSize: 'var(--font-size-sm)' }}>
        {dob} ({age}y) | {sex} | PHN: {hin}
      </span>
      {allergies.length > 0 && (
        <Badge variant="error">{allergies.length} allergy{allergies.length > 1 ? 's' : ''}</Badge>
      )}
    </div>
    {providerName && (
      <span style={{ opacity: 0.8, fontSize: 'var(--font-size-sm)' }}>Dr. {providerName}</span>
    )}
  </div>
);

// Vitals panel
interface Vital {
  label: string;
  value: string;
  unit: string;
  trend?: 'up' | 'down' | 'stable';
}

interface VitalsPanelProps {
  vitals: Vital[];
}

const trendColors: Record<string, string> = { up: 'var(--color-error)', down: 'var(--color-success)', stable: 'var(--color-neutral-400)' };

export const VitalsPanel: React.FC<VitalsPanelProps> = ({ vitals }) => (
  <Card title="Vitals">
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(100px, 1fr))', gap: 'var(--spacing-3)' }}>
      {vitals.map((v, i) => (
        <div key={i} style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 'var(--font-size-2xl)', fontWeight: 700 }}>{v.value}</div>
          <div style={{ fontSize: 'var(--font-size-xs)', color: 'var(--color-neutral-500)' }}>
            {v.label} ({v.unit})
            {v.trend && <span style={{ color: trendColors[v.trend], marginLeft: 4 }}>{v.trend === 'up' ? '↑' : v.trend === 'down' ? '↓' : '→'}</span>}
          </div>
        </div>
      ))}
    </div>
  </Card>
);

// Medication list
interface Medication {
  name: string;
  dose: string;
  route: string;
  frequency: string;
  startDate: string;
  interactions?: string[];
}

interface MedicationListProps {
  medications: Medication[];
}

export const MedicationList: React.FC<MedicationListProps> = ({ medications }) => (
  <Card title="Current Medications">
    {medications.length === 0 ? (
      <p style={{ color: 'var(--color-neutral-400)', fontStyle: 'italic' }}>No active medications</p>
    ) : (
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <tbody>
          {medications.map((med, i) => (
            <tr key={i} style={{ borderBottom: '1px solid var(--color-neutral-100)' }}>
              <td style={{ padding: 'var(--spacing-2)', fontWeight: 500 }}>{med.name}</td>
              <td style={{ padding: 'var(--spacing-2)', color: 'var(--color-neutral-500)' }}>{med.dose} {med.route} {med.frequency}</td>
              <td style={{ padding: 'var(--spacing-2)', color: 'var(--color-neutral-400)', fontSize: 'var(--font-size-sm)' }}>Since {med.startDate}</td>
            </tr>
          ))}
        </tbody>
      </table>
    )}
  </Card>
);

// Allergy badge (clinical)
interface AllergyBadgeProps {
  allergies: { name: string; severity: 'mild' | 'moderate' | 'severe' }[];
}

const severityMap: Record<string, 'error' | 'warning' | 'neutral'> = {
  severe: 'error', moderate: 'warning', mild: 'neutral',
};

export const AllergyBadge: React.FC<AllergyBadgeProps> = ({ allergies }) => (
  <div style={{ display: 'flex', gap: 'var(--spacing-1)', flexWrap: 'wrap' }}>
    {allergies.length === 0 ? (
      <Badge variant="success">No known allergies</Badge>
    ) : (
      allergies.map((a, i) => <Badge key={i} variant={severityMap[a.severity]}>{a.name}</Badge>)
    )}
  </div>
);

// Problem list
interface Problem {
  code: string;
  name: string;
  onsetDate: string;
  status: 'active' | 'resolved';
}

interface ProblemListProps {
  problems: Problem[];
}

export const ProblemList: React.FC<ProblemListProps> = ({ problems }) => (
  <Card title="Active Problems">
    {problems.length === 0 ? (
      <p style={{ color: 'var(--color-neutral-400)', fontStyle: 'italic' }}>No active problems</p>
    ) : (
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <tbody>
          {problems.map((p, i) => (
            <tr key={i} style={{ borderBottom: '1px solid var(--color-neutral-100)' }}>
              <td style={{ padding: 'var(--spacing-2)', fontWeight: 500 }}>{p.name}</td>
              <td style={{ padding: 'var(--spacing-2)', color: 'var(--color-neutral-400)', fontFamily: 'var(--font-mono)', fontSize: 'var(--font-size-sm)' }}>{p.code}</td>
              <td style={{ padding: 'var(--spacing-2)', color: 'var(--color-neutral-500)', fontSize: 'var(--font-size-sm)' }}>Since {p.onsetDate}</td>
            </tr>
          ))}
        </tbody>
      </table>
    )}
  </Card>
);
